import os
import platform
from core.plugin_manager import StuartPlugin
from typing import Dict, Any

class SystemMonitorPlugin(StuartPlugin):
    name = "SystemMonitor"
    version = "1.0.0"
    description = "Reports system CPU, memory, and disk stats."

    def on_load(self, context: Dict[str, Any]):
        slash = context.get('slash_router')
        if slash:
            slash.register_command('/sysmon', self._cmd_sysmon, 'Show system resource usage')
        logger = context.get('logger')
        if logger:
            logger.info('SystemMonitorPlugin loaded.')

    def _cmd_sysmon(self, args: str) -> str:
        try:
            import shutil
            total, used, free = shutil.disk_usage('/')
            lines = [
                '\U0001f4bb **System Monitor**',
                f'  OS: {platform.system()} {platform.release()}',
                f'  Python: {platform.python_version()}',
                f'  Disk Total: {total // (1024**3)} GB',
                f'  Disk Used:  {used // (1024**3)} GB',
                f'  Disk Free:  {free // (1024**3)} GB',
            ]
            return '\n'.join(lines)
        except Exception as e:
            return f'Error: {e}'

import threading
import time
from core.plugin_manager import StuartPlugin
from typing import Dict, Any

class PomodoroPlugin(StuartPlugin):
    name = "Pomodoro"
    version = "1.0.0"
    description = "A simple Pomodoro focus timer."

    def on_load(self, context: Dict[str, Any]):
        self._logger = context.get('logger')
        slash = context.get('slash_router')
        if slash:
            slash.register_command('/pomodoro', self._cmd_pomodoro, 'Start a 25-min Pomodoro timer: /pomodoro [minutes]')
        if self._logger:
            self._logger.info('PomodoroPlugin loaded.')

    def _cmd_pomodoro(self, args: str) -> str:
        minutes = 25
        if args.strip().isdigit():
            minutes = int(args.strip())
        def _timer():
            time.sleep(minutes * 60)
            if self._logger:
                self._logger.info(f'Pomodoro complete! {minutes} minutes elapsed.')
        t = threading.Thread(target=_timer, daemon=True)
        t.start()
        return f'\U0001f345 Pomodoro started! Timer set for **{minutes} minutes**. You will see a log entry when it completes.'
